            quoted_filename = iri_to_uri(f'{safe_name}_codes.zip')

            response['Content-Disposition'] = f"attachment; filename*=UTF-8''{quoted_filename}"

            return response

        except Exception as e:
            return HttpResponseServerError(f"An error occurred: {str(e)}")

