def base_contest_ranking_list(contest, problems, queryset):
    # return [make_contest_ranking_profile(contest, participation, problems) for participation in
    #         queryset.select_related('user__user', 'rating').defer('user__about', 'user__organizations__about')]
    return [make_contest_ranking_profile(contest, participation, problems) for participation in
            queryset.select_related('user__user', 'rating').defer('user__about')]


def contest_ranking_list(contest, problems):
    # 기본 정렬로 참가자 목록 가져오기
    participants = base_contest_ranking_list(contest, problems, contest.users.filter(virtual=0)
                                    #  .prefetch_related('user__organizations')
                                    .order_by('is_disqualified', '-score', 'cumtime', 'tiebreaker'))

    # Python에서 제출 횟수 추가 및 재정렬
    for participant in participants:
        participant.submission_count = participant.participation.submissions.count()

    # 정렬: 실격 여부 → 점수 → 시간 → 타이브레이커 → 제출 횟수 (내림차순) → 학번
    participants.sort(key=lambda p: (
        p.participation.is_disqualified,
        -p.points,
        p.cumtime,
        p.tiebreaker,
        -p.submission_count,  # 제출 많은 순
        p.user.user.username  # 학번순
    ))

    return participants


def get_contest_ranking_list(request, contest, participation=None, ranking_list=contest_ranking_list,
                             show_current_virtual=True, ranker=ranker):
    problems = list(contest.contest_problems.select_related('problem').defer('problem__description').order_by('order'))

    users = ranker(ranking_list(contest, problems), key=attrgetter('points', 'cumtime', 'tiebreaker'))

    if show_current_virtual:
        if participation is None and request.user.is_authenticated:
            participation = request.profile.current_contest
            if participation is None or participation.contest_id != contest.id:
                participation = None
        if participation is not None and participation.virtual:
            users = chain([('-', make_contest_ranking_profile(contest, participation, problems))], users)
    return users, problems


