        if 'subject_id' in request.GET:
            try:
                self.subject_ids = list(map(int, request.GET.getlist('subject_id')))
            except ValueError:
                pass

        return super(ContestListMixin, self).get(request, *args, **kwargs)
    def get_queryset(self):
